import React from "react";

function Header() {
  return (
    <header style={styles.navbar}>
      <h2 style={styles.logo}>DocBook</h2>
      <ul style={styles.navLinks}>
        <li>Home</li>
        <li>Doctors</li>
        <li>My Appointments</li>
        <li>Profile</li>
        <li style={styles.logout}>Logout</li>
      </ul>
    </header>
  );
}

export default Header;

const styles = {
  navbar: {
    backgroundColor: "#2c3e50",
    color: "white",
    padding: "15px 30px",
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
  },

  logo: {
    margin: 0,
  },

  navLinks: {
    listStyle: "none",
    display: "flex",
    gap: "20px",
    margin: 0,
    padding: 0,
    cursor: "pointer",
  },

  logout: {
    color: "#e74c3c",
    fontWeight: "bold",
  },
};
